import { Component, OnInit } from '@angular/core';
import { NavigationEnd, Router } from '@angular/router';
import { AuthService } from './core/services/auth.service';
import { filter } from 'rxjs/operators';

@Component({
  selector: 'app-root',
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.css']
})
export class AppComponent implements OnInit {
  title = 'sponsorship-ui';
  isSidebarCollapsed = false;
  isLoggedIn = false;
  isLoginPage = false;

  constructor(
    private authService: AuthService,
    private router: Router
  ) {}

  ngOnInit() {
    // Check login status
    this.authService.currentUser$.subscribe(user => {
      this.isLoggedIn = !!user;
      this.checkIfLoginPage();
    });

    // Check route changes
    this.router.events.pipe(
      filter(event => event instanceof NavigationEnd)
    ).subscribe(() => {
      this.checkIfLoginPage();
    });
  }

  checkIfLoginPage() {
    const currentUrl = this.router.url;
    this.isLoginPage = currentUrl.includes('/login') || currentUrl === '/' || currentUrl === '';

    // If on login page, force hide sidebar and header
    if (this.isLoginPage) {
      this.isLoggedIn = false;
    } else {
      // Re-check login status
      this.isLoggedIn = this.authService.isLoggedIn();
    }
  }

  toggleSidebar() {
    this.isSidebarCollapsed = !this.isSidebarCollapsed;
  }
}
<div class="app-container">
  <!-- Check if current route is login page -->
  <ng-container *ngIf="!(router.url === '/login' || router.url === '/')">
    <!-- Sidebar - Show only when NOT on login page -->
    <div class="sidebar-wrapper" [class.collapsed]="isSidebarCollapsed">
      <app-sidebar (toggleSidebar)="toggleSidebar()"></app-sidebar>
    </div>

    <!-- Main Content with Sidebar -->
    <div class="main-wrapper" [class.sidebar-collapsed]="isSidebarCollapsed">
      <app-header (toggleSidebar)="toggleSidebar()"></app-header>
      <div class="content-wrapper">
        <div class="container-fluid">
          <router-outlet></router-outlet>
        </div>
      </div>
    </div>
  </ng-container>

  <!-- Login Page - No Sidebar, No Header -->
  <ng-container *ngIf="(router.url === '/login' || router.url === '/')">
    <div class="login-fullscreen">
      <router-outlet></router-outlet>
    </div>
  </ng-container>
</div>
